<div class="card"><div class="card-head"><h3>All Transactions</h3></div><form method="get" action="<?= base_url('index.php') ?>" class="filter-form"><input type="hidden" name="route" value="admin/transactions"><input type="text" name="search" placeholder="Search user or reference" value="<?= e($filters['search']) ?>"><input type="text" name="type" placeholder="Type" value="<?= e($filters['type']) ?>"><input type="text" name="status" placeholder="Status" value="<?= e($filters['status']) ?>"><button class="btn btn-outline" type="submit">Filter</button></form><div class="table-wrap"><table><thead><tr><th>Reference</th><th>User</th><th>Type</th><th>Direction</th><th>Amount</th><th>Status</th><th>Date</th></tr></thead><tbody><?php foreach ($transactions as $tx): ?><tr><td><?= e($tx['reference_no']) ?></td><td><?= e($tx['name']) ?> <small>(<?= e($tx['email']) ?>)</small></td><td><?= e($tx['type']) ?></td><td><?= e($tx['direction']) ?></td><td><?= money((float)$tx['amount']) ?></td><td><?= e($tx['status']) ?></td><td><?= e($tx['created_at']) ?></td></tr><?php endforeach; ?><?php if (!$transactions): ?><tr><td colspan="7">No transactions found.</td></tr><?php endif; ?></tbody></table></div></div>
